external_knowledge:
- The 'top league' refers to the league with a league_id of 0; 
- The 'first season' is identified by a season_id of 1; 
- Total goals scored by a team include both home and away goals.

sql:
SELECT MAX(total_points) AS max_cumulative_points
FROM (
    SELECT team_id, SUM(points) AS total_points
    FROM teams
    GROUP BY team_id
) AS team_points;
